54	char* eep_get_tpu_version(unsigned int rdval)
55	{
56	    // hw_v2[5:0].hw_v1[5:0].hw_v0[5:0].hw_r0[5:0].hw_p0[7:0]
57	    unsigned int v1 = (rdval >> 26) & 0x3f;
58	    unsigned int v2 = (rdval >> 20) & 0x3f;
59	    unsigned int v3 = (rdval >> 14) & 0x3f;
60	    unsigned int r = (rdval >> 8) & 0x3f;
61	    unsigned int p = (rdval >> 0) & 0xff;
62	    sprintf(tpuver_str, "%d.%d.%d-r%d-p%d", v1, v2, v3, r, p);
63	    return tpuver_str;
64	}
