126	
127	    bin_type = *pcfg++;
128	    mem_cnt = *pcfg++;
129	    if (bin_type == 1)
130	    {
131	        hwbase0 = (*pcfg++) + mem_base;
132	        hwbase1 = (*pcfg++) + mem_base;
133	    }
134	    else if (bin_type == 2)
135	    {
136	        hwbase0 = (*pcfg++) + mem_base;
137	        hwbase1 = (*pcfg++) + mem_base;
138	        hwbase2 = (*pcfg++) + mem_base;
139	        hwbase3 = (*pcfg++) + mem_base;
140	    }
141	
142	    memsize = *pcfg++;
143	    int cnt_out = *pcfg++;
144	    printf("output cnt = %d\n", cnt_out);
145	    //if (cfglen < ( 8*4 + cnt_out*6*4 + 1*4 ) ) return -1;
146	    for (int i = 0; i < cnt_out; i++)
147	    {
148	        struct st_hwaddr_info info;
149	        info.hwaddr = (*pcfg++) + mem_base;
150	        info.shape[0] = *pcfg++;
151	        info.shape[1] = *pcfg++;
152	        info.shape[2] = *pcfg++;
153	        info.shape[3] = *pcfg++;
154	        info.exp = *pcfg++;
155	        printf("out[%d]: hwaddr 0x%08x, shape: %d,%d,%d,%d\n", i, info.hwaddr, info.shape[0], info.shape[1], info.shape[2], info.shape[3]);
156	        addr_out.push_back(info);
157	    }
158	    int cnt_threads = *pcfg++;
159	    addr_alg = (*pcfg++) + mem_base;
160	    *pcfg++;
161	    {
162			addr_in.hwaddr = (*pcfg++) + mem_base;
163			addr_in.shape[0] = *pcfg++;
164			addr_in.shape[1] = *pcfg++;
165			addr_in.shape[2] = *pcfg++;
166			addr_in.shape[3] = *pcfg++;
167			addr_in.exp = *pcfg++;
168			printf("in: hwaddr 0x%08x, shape: %d,%d,%d,%d\n", addr_in.hwaddr, addr_in.shape[0], addr_in.shape[1], addr_in.shape[2], addr_in.shape[3]);
169		}
170	    int in_ch = *pcfg++;  mean.clear(); norm.clear();
171	    for (int i = 0; i < in_ch; i++) { mean.push_back(*(float*)pcfg); pcfg++; }
172	    for (int i = 0; i < in_ch; i++) { norm.push_back(*(float*)pcfg); pcfg++; }
173	
174	    // ------ read config done.
175	    //printf("interface = %d\n", interface);
176	    printf("mem_base = 0x%08lx\n", mem_base);
