EEPTPU_SA::EEPTPU_SA()
{
    //tpu_hwbase_count = 2;
    //tpu_hwbase = (unsigned int*)malloc(tpu_hwbase_count * sizeof(unsigned int));
    //memset(tpu_hwbase, 0, tpu_hwbase_count * sizeof(unsigned int));
    b_terminate = false;

    b_ex = false;

    interface = 0;
    mem_base = 0;
    hwbase0 = 0;
